const data = $input.first().json;
// Only clients who've actually started billing have anything to reconcile
const clients = (data.list || []).filter(c => c.stripe_customer_id && c.stripe_customer_id.trim());
return clients.map(c => ({ json: c }));

const client = $('Loop clients').first().json;
const cust = $('HTTP · Get Stripe customer').first().json;
const subsResp = $('HTTP · Get Stripe subscriptions').first().json;
const subs = subsResp.data || [];

// Prefer a live subscription (active/trialing/past_due); fall back to the most recently
// created of any status so a fully-canceled account still gets its status corrected.
const live = subs.find(s => ['active','trialing','past_due'].includes(s.status))
          || subs.slice().sort((a,b) => (b.created||0)-(a.created||0))[0]
          || null;

const nocoPatch = {};
const noteLines = [];

if (live) {
  const priceItem = live.items?.data?.[0]?.price;
  const liveStatus = live.status;
  const liveRenews = live.current_period_end ? new Date(live.current_period_end * 1000).toISOString() : '';
  const liveCancelAtEnd = live.cancel_at_period_end ? 'Yes' : 'No';
  const livePlanName = priceItem?.nickname || '';

  if ((client.stripe_subscription_id||'') !== live.id) { nocoPatch.stripe_subscription_id = live.id; noteLines.push(`subscription id ${client.stripe_subscription_id||'(none)'} → ${live.id}`); }
  if ((client.plan_status||'') !== liveStatus) { nocoPatch.plan_status = liveStatus; noteLines.push(`status ${client.plan_status||'(none)'} → ${liveStatus}`); }
  if (liveRenews && (client.plan_renews_at||'') !== liveRenews) { nocoPatch.plan_renews_at = liveRenews; noteLines.push('renews_at updated to match Stripe'); }
  if ((client.plan_cancel_at_period_end||'No') !== liveCancelAtEnd) { nocoPatch.plan_cancel_at_period_end = liveCancelAtEnd; noteLines.push(`cancel_at_period_end → ${liveCancelAtEnd}`); }
  if (livePlanName && (client.plan_name||'') !== livePlanName) { nocoPatch.plan_name = livePlanName; noteLines.push(`plan_name → ${livePlanName}`); }
} else if (client.stripe_subscription_id || (client.plan_status && client.plan_status !== 'canceled')) {
  // Stripe shows no subscription at all for this customer, but NocoDB thinks there's a live one —
  // most likely a missed/failed webhook (customer.subscription.deleted never landed).
  nocoPatch.plan_status = 'canceled';
  noteLines.push(`no Stripe subscription found — marked canceled (was "${client.plan_status||'unknown'}")`);
}

// The billing email must always mirror the billing profile (authentik_email) — that's the
// single source of truth, and Checkout locks the email field once the Customer already has one
// set, so it can't drift at payment time. Drift here means the Customer object was edited
// directly (Stripe Dashboard, API, or a pre-authentik legacy customer) — restore it.
const wantEmail = (client.authentik_email||'').trim();
const custEmail = (cust.email||'').trim();
const needsEmailFix = !!wantEmail && wantEmail.toLowerCase() !== custEmail.toLowerCase();
if (needsEmailFix) noteLines.push(`billing email "${custEmail||'(none)'}" → "${wantEmail}" (restored from billing profile)`);

const needsNocoPatch = Object.keys(nocoPatch).length > 0;
if (!needsNocoPatch && !needsEmailFix) return [];

return [{ json: {
  clientId: client.Id, clientName: client.client_name,
  notification_email: client.notification_email || '', slack_webhook_url: client.slack_webhook_url || '',
  stripe_customer_id: client.stripe_customer_id,
  needsNocoPatch, nocoPatch, needsEmailFix, correctEmail: wantEmail, noteLines
} }];

const c = $input.first().json;
const lines = c.noteLines || [];
return [{ json: {
  to: c.notification_email,
  slack_webhook_url: c.slack_webhook_url,
  subject: '🔄 Billing reconciliation: ' + (c.clientName || c.clientId),
  body: `Reconciliation found and corrected billing drift for ${c.clientName || 'client '+c.clientId}:\n\n`
    + lines.map(l => '• ' + l).join('\n')
    + '\n\nThis was corrected automatically from live Stripe data — no action needed unless something looks wrong.'
} }];
